/// <summary>
/// Inserts records into the temporary <c>ETG_custAgingReportTmp</c> table.
/// </summary>
/// <param name="_reverseAmountsAndHeadings">
/// A boolean value which indicates whether the column values should be reversed.
/// </param>
/// <param name="_tmpTableRecordList">
///    An existing RecordInsertList, which is used to store custAgingReportTmp records for bulk insert.
/// </param>
//protected void insertcustAgingReportTmp(boolean _reverseAmountsAndHeadings, RecordInsertList _tmpTableRecordList)
protected void insertcustAgingReportTmp(boolean _reverseAmountsAndHeadings)
{
    CustVendTransAging custVendTransAging = custVendBalanceList.getCustVendTransAging();

    ETG_CustAgingReportDPParameters custAgingReportDPParameters = ETG_CustAgingReportDPParameters::construct();

    // vendAgingReportDPParameters.custaf = custAgingReportTmp;
    custAgingReportDPParameters.custAgingReportTmp = custAgingReportTmp;
    custAgingReportDPParameters.custTmpAccountSum = tmpAccountSum;
    custAgingReportDPParameters.custVendTransAging = custVendTransAging;

    custAgingReportDPParameters.reverseAmountsAndHeadings = _reverseAmountsAndHeadings;
    custAgingReportDPParameters.ledgerCurrencySelection = contract.parmCurrencySelection();
    custAgingReportDPParameters.headingDate = headingDate;
    custAgingReportDPParameters.heading01 = heading01;
    custAgingReportDPParameters.heading011 = heading011;
    custAgingReportDPParameters.heading02 = heading02;
    custAgingReportDPParameters.heading02Text = heading02Text;
    custAgingReportDPParameters.heading021 = heading021;
    custAgingReportDPParameters.heading03 = heading03;
    custAgingReportDPParameters.heading031 = heading031;
    custAgingReportDPParameters.heading04 = heading04;
    custAgingReportDPParameters.heading041 = heading041;
    custAgingReportDPParameters.heading05 = heading05;
    custAgingReportDPParameters.heading051 = heading051;
    custAgingReportDPParameters.heading06 = heading06;
    custAgingReportDPParameters.heading061 = heading061;
    custAgingReportDPParameters.heading07 = heading07;
    custAgingReportDPParameters.heading071 = heading071;
    custAgingReportDPParameters.heading08   = heading08;
    custAgingReportDPParameters.heading081  = heading081;
    custAgingReportDPParameters.heading09   = heading09;
    custAgingReportDPParameters.heading091  = heading091;
    custAgingReportDPParameters.heading10   = heading10;
    custAgingReportDPParameters.heading101  = heading101;
    custAgingReportDPParameters.heading10Text = heading10Text;
    custAgingReportDPParameters.headingAgingBucketDescription02 = headingAgingBucketDescription02;
    custAgingReportDPParameters.headingAgingBucketDescription03 = headingAgingBucketDescription03;
    custAgingReportDPParameters.headingAgingBucketDescription04 = headingAgingBucketDescription04;
    custAgingReportDPParameters.headingAgingBucketDescription05 = headingAgingBucketDescription05;
    custAgingReportDPParameters.headingAgingBucketDescription06 = headingAgingBucketDescription06;
    custAgingReportDPParameters.headingAgingBucketDescription07 = headingAgingBucketDescription07;
    custAgingReportDPParameters.headingAgingBucketDescription08 = headingAgingBucketDescription08;
    custAgingReportDPParameters.headingAgingBucketDescription09 = headingAgingBucketDescription09;
    custAgingReportDPParameters.headingAgingBucketDescription10 = headingAgingBucketDescription10;
    custAgingReportDPParameters.headingAgingBucketDescription11 = headingAgingBucketDescription11;
    custAgingReportDPParameters.headingAccount = "@SYS24500";
    custAgingReportDPParameters.headingName = "@SYS7399";
    custAgingReportDPParameters.balance = 100;
    custAgingReportDPParameters.asOfDate = strFmt("@SYS84682", date2StrUsr(contract.parmBalanceAsOfDate(), DateFlags::FormatAll), contract.parmDateTransactionDuedate());

    ETG_CustAgingReportTmpFromCustTmpAccountSum custAgingReportTmpFromCustTmpAccountSum = ETG_CustAgingReportTmpFromCustTmpAccountSum::newFromCustAgingReportDP(custAgingReportDPParameters);
    custAgingReportTmpFromCustTmpAccountSum.execute();
}

public boolean parmUseDefaultTransactionOnly(boolean _useDefaultTransOnly = useDefaultTransOnly)
{
    useDefaultTransOnly = true;
    return useDefaultTransOnly;
}

/// <summary>
/// Processes the report business logic.
/// </summary>
/// <remarks>
/// This method is used to process the report business logic which is used by the <c>VendAgingReport</c> report.
/// </remarks>
public void processReport()
{
    QueryRun qr;
    ForwardBackwardPrinting tmpDirection;
    boolean reverseAmountsAndHeadings;
    //RecordInsertList tmpTableRecordList = new RecordInsertList(tableNum(ETG_custAgingReportTmp), true, true, true, false, true, custAgingReportTmp);

    contract = this.parmDataContract() as ETG_CustAgingReportContract;

    financialDimensions             = contract.parmFinancialDimensions();
    financialDimSet                 = contract.parmFinancialDimSet();

    qr = new QueryRun(this.parmQuery());

    if (!contract.parmZeroDate())
    {
        // When zero date is not given then use the system session date.
        contract.parmZeroDate(DateTimeUtil::getSystemDate(DateTimeUtil::getUserPreferredTimeZone()));
    }

    if (!contract.parmBalanceAsOfDate())
    {
        // When the balance as of date is not given then use the max date.
        contract.parmBalanceAsOfDate(dateMax());
    }

    if (contract.parmAgingBuckets())
    {
        // Force layout direction to backwards,
        // the actual direction of the columns is done in the construct method of the class: CustVendBalanceList
        tmpDirection = StatRepInterval::find(contract.parmAgingBuckets()).PrintDirection;
    }
    else
    {
        tmpDirection = contract.parmDirection();
    }

    reverseAmountsAndHeadings = this.getReverseAmountsAndHeadings(contract.parmAgingBuckets(), tmpDirection);

    custVendBalanceList = ETG_CustVendBalanceList::construct(SysModule::Cust,
                                                            contract.parmDateTransactionDuedate(),
                                                            contract.parmInterval(),
                                                            contract.parmBalanceAsOfDate(),
                                                            contract.parmZeroDate(),
                                                            contract.parmPayments(),
                                                            contract.parmPeriod(),
                                                            tmpDirection,
                                                            contract.parmAgingBuckets(),
                                                            NoYes::Yes,
                                                            contract.parmDetailed(),
                                                            null,
                                                            NoYes::No,
                                                            contract.parmExcludeZeroBalanceVendor(),
                                                            !contract.parmPrintZeroOrNegative());

    custVendBalanceList.calculateDetailsForMultiple(qr, CustVendAgingQueryConverter::convertCustomers(qr.query()), contract.parmIncludeAmountCur());
    tmpAccountSum = custVendBalanceList.initTmpAccountSum();

    this.initHeadingValues();

    //this.insertcustAgingReportTmp(reverseAmountsAndHeadings, tmpTableRecordList);
    this.insertcustAgingReportTmp(reverseAmountsAndHeadings);

    if (contract.parmDetailed())
    {
        this.updatecustAgingReportTmp();
    }
    else
    {
        this.updateCustAgingReportTmpNonDet();
    }

}

public Description getFinDimValue(DimensionDefault _defaultDimension, Name     _dimensionName)
{
    DimensionAttributeValueSetStorage   dimStorage;
    DimensionAttribute                  dimAttribute;
    DimensionValue                      displayValue = "";
    Description                         dimDescription = "";
    int                                 i;

    dimStorage = DimensionAttributeValueSetStorage::find(_defaultDimension);
    for (i= 1 ; i<= dimStorage.elements() ; i++)
    {
        dimAttribute    = DimensionAttribute::find(dimStorage.getAttributeByIndex(i));

        if(dimAttribute.Name == _dimensionName)
        {
            displayValue    = dimStorage.getDisplayValueByIndex(i);
            dimDescription  = DimensionFinancialTag::findByFinancialTagCategoryAndValue(dimAttribute.financialTagCategory(), displayValue).Description;
            if (dimDescription == "")
            {
                dimDescription  = this.getFinDimValueDescription(dimAttribute.ViewName, displayValue);
            }
        }
    }

    return  dimDescription;
}

public Description getFinDimValueDescription(TableNameShort     _ViewName, DimensionValue   _displayValue)
{
    DimAttributeInventTable         inventTable;
    DimAttributeHcmWorker           worker;
    DimAttributeCustTable           custTable;
    DimAttributeVendTable           dimVendTable;
    DimAttributeAssetTable          assetTable;
    DimAttributeOMBusinessUnit      businessUnit;
    DimAttributeOMCostCenter        costCenter;
    DimAttributeOMDepartment        department;
    Description                     dimDescription = "";

    switch (_ViewName)
    {
        case  "DimAttributeInventTable":
            select Name from inventTable
                where inventTable.value == _displayValue;
            dimDescription = inventTable.Name;
            break;
        case  "DimAttributeHcmWorker":
            select Name from worker
                where worker.value == _displayValue;
            dimDescription = worker.Name;
            break;
        case  "DimAttributeCustTable":
            select Name from custTable
                where custTable.value == _displayValue;
            dimDescription = custTable.Name;
            break;
        case  "DimAttributeVendTable":
            select Name from dimVendTable
                where dimVendTable.value == _displayValue;
            dimDescription = dimVendTable.Name;
            break;
        case  "DimAttributeAssetTable":
            select Name from assetTable
                where assetTable.value == _displayValue;
            dimDescription = assetTable.Name;
            break;
        case  "DimAttributeOMBusinessUnit":
            select Name from businessUnit
                where businessUnit.value == _displayValue;
            dimDescription = businessUnit.Name;
            break;
        case  "DimAttributeOMCostCenter":
            select Name from costCenter
                where costCenter.value == _displayValue;
            dimDescription = costCenter.Name;
            break;
        case  "DimAttributeOMDepartment":
            select Name from department
                where department.value == _displayValue;
            dimDescription = department.Name;
            break;
    }

    return      dimDescription;
}

public void updateCustAgingReportTmpNonDet()
{
    CustTrans                       custtransUpdBal8,custtransUpdBal9,custtransUpdBal10;

    ttsbegin;
    while select forupdate custAgingReportTmp
    {

        select sum(AmountMST),TransDate from custtransUpdBal8
            where custtransUpdBal8.AccountNum   ==  custAgingReportTmp.AccountNum &&
                  custtransUpdBal8.CurrencyCode == custAgingReportTmp.Currency  &&
                  (custtransUpdBal8.TransDate  >=  custAgingReportTmp.Heading8  &&
                   custtransUpdBal8.TransDate  <=  custAgingReportTmp.Heading18) ;
        if(custtransUpdBal8)
        {
            custAgingReportTmp.Balance08NonDet = custtransUpdBal8.AmountMST;
        }
        select sum(AmountMST),TransDate from custtransUpdBal9
            where custtransUpdBal9.AccountNum ==  custAgingReportTmp.AccountNum &&
                  custtransUpdBal9.CurrencyCode == custAgingReportTmp.Currency  &&
                  (custtransUpdBal9.TransDate  >=  custAgingReportTmp.Heading9  &&
                  custtransUpdBal9.TransDate  <=  custAgingReportTmp.Heading19) ;
        if(custtransUpdBal9)
        {
            custAgingReportTmp.Balance09NonDet = custtransUpdBal9.AmountMST;
        }
        select sum(AmountMST),TransDate from custtransUpdBal10
            where custtransUpdBal10.AccountNum ==  custAgingReportTmp.AccountNum &&
                  custtransUpdBal10.CurrencyCode == custAgingReportTmp.Currency  &&
                  (custtransUpdBal10.TransDate  <=  custAgingReportTmp.Heading20);
        if(custtransUpdBal10)
        {
            custAgingReportTmp.Balance10NonDet = custtransUpdBal10.AmountMST;
        }
        GeneralJournalEntry journalEntry;
        GeneralJournalAccountEntry accountEntry;
        select firstOnly journalEntry
            where journalEntry.SubledgerVoucher == custAgingReportTmp.Voucher;

        if (journalEntry.RecId)
        {
            select firstOnly accountEntry
            where accountEntry.GeneralJournalEntry == journalEntry.RecId;

            if (accountEntry.RecId)
            {
                custAgingReportTmp.ETGCommodity = ETGGeneralJournalAccountEntry_Extension::commodity(accountEntry);
                //vendAgingReportTmp.ETGSubCommodity = ETGGeneralJournalAccountEntry_Extension::su(accountEntry);
                custAgingReportTmp.ETGVertical = ETGGeneralJournalAccountEntry_Extension::Vertical(accountEntry);
                custAgingReportTmp.ETGSubVertical = ETGGeneralJournalAccountEntry_Extension::subVertical(accountEntry);
            }
        }

        custAgingReportTmp.update();
    }
    ttscommit;
}

